const crypto = require('crypto');
const appId = 'scaleupally-fQavn';
// const appSecret = 'J1lPpNlRF3y7DBzoofGOBV-H';
const privateKeyB64 = 'MIGHAgEAMBMGByqGSM49AgEGCCqGSM49AwEHBG0wawIBAQQgRSunJaKB66aEHQnWDXfLuUgy8GzE/92GNBD4+G/lsHehRANCAAQ9pAoh0RYvYNB3vHhLgqWcXi+6Gqg0WhTuXdK7tnah2Phg0n+vONjiGyT/OdE3u5XMf0LsNegz5YEx4+1s4yzD';

function b64url(s) {
  return Buffer.from(s).toString('base64')
    .replace(/=/g,'').replace(/\+/g,'-').replace(/\//g,'_');
}

const header = b64url(JSON.stringify({ alg: 'ES256', typ: 'JWT' }));
const now = Math.floor(Date.now() / 1000);
const payload = b64url(JSON.stringify({
  iss: appId,
  aud: 'serana',
  sub: appId,
  auth: {
    entity: 'app',
    strategy: 'app-iss-app-token'
  },
  iat: now,
  exp: now + 3600
}));

const signingInput = header + '.' + payload;
const privateKey = crypto.createPrivateKey({
  key: Buffer.from(privateKeyB64, 'base64'),
  format: 'der',
  type: 'pkcs8'
});
const signature = crypto
  .sign('sha256', Buffer.from(signingInput), { key: privateKey, dsaEncoding: 'ieee-p1363' })
  .toString('base64')
  .replace(/=/g,'').replace(/\+/g,'-').replace(/\//g,'_');

return [{ json: { token: signingInput + '.' + signature } }];

